import sys
import click
from pathlib import Path

sys.path.insert(0, str(Path(__file__).parent))

from analyser import ProjectAnalyzer
from fixer.agent import FixerAgent

@click.group()
def cli():
    """CLI principal do Agente Independente."""
    pass

@cli.command()
@click.argument('path', type=click.Path(exists=True))
@click.option('--json', is_flag=True)
def analyze(path, json_flag):
    analyzer = ProjectAnalyzer(path)
    issues = analyzer.analyze()
    if json_flag:
        import json
        click.echo(json.dumps([vars(i) for i in issues], indent=2, ensure_ascii=False))
    else:
        for issue in issues:
            click.echo(str(issue))

@cli.command()
@click.argument('path', type=click.Path(exists=True))
@click.option('--dry-run', is_flag=True)
def fix(path, dry_run):
    agent = FixerAgent(path)
    if dry_run:
        issues = agent.analyzer.analyze()
        for i in issues:
            click.echo(str(i))
    else:
        agent.fix()

if __name__ == '__main__':
    cli()

import ast
import os
from pathlib import Path
from typing import List

class Issue:
    def __init__(self, file_path: str, line: int, type_: str, message: str):
        self.file_path = file_path
        self.line = line
        self.type = type_
        self.message = message

    def __str__(self):
        if self.line > 0:
            return f"{self.file_path}:{self.line} [{self.type}] {self.message}"
        return f"[{self.type}] {self.message}"

class ProjectAnalyzer:
    def __init__(self, project_root: str):
        self.root = Path(project_root).resolve()

    def analyze(self) -> List[Issue]:
        issues = []
        issues.extend(self._check_structure())
        for py_file in self._find_python_files():
            rel_path = py_file.relative_to(self.root).as_posix()
            file_issues = self._analyze_python_file(py_file)
            for i in file_issues:
                i.file_path = rel_path
                issues.append(i)
        return issues

    def _check_structure(self) -> List[Issue]:
        issues = []
        if not (self.root / "src").exists():
            issues.append(Issue("", 0, "structure", "Diretório src/ ausente"))
        if not (self.root / "tests").exists():
            issues.append(Issue("", 0, "structure", "Diretório tests/ ausente"))
        if not any(self.root.glob("pyproject.toml")) and not any(self.root.glob("setup.py")):
            issues.append(Issue("", 0, "structure", "Arquivo de configuração de build ausente"))
        return issues

    def _find_python_files(self) -> List[Path]:
        return [
            p for p in self.root.rglob("*.py")
            if 'venv' not in p.parts and '__pycache__' not in p.parts
        ]

    def _analyze_python_file(self, file_path: Path) -> List[Issue]:
        issues = []
        try:
            source = file_path.read_text(encoding='utf-8')
            tree = ast.parse(source)
            lines = source.splitlines()
            max_len = max((len(line) for line in lines), default=0)
            if max_len > 79:
                issues.append(Issue(file_path.name, 0, "pep8", f"Linha muito longa (max {max_len} > 79)"))
            if not ast.get_docstring(tree):
                issues.append(Issue(file_path.name, 0, "docstring", "Docstring do módulo ausente"))
        except SyntaxError as e:
            issues.append(Issue(file_path.name, e.lineno or 0, "syntax", str(e).splitlines()[0]))
        return issues

from pathlib import Path
from analyser.project_analyzer import ProjectAnalyzer, Issue
from .core import PythonFixer

class FixerAgent:
    def __init__(self, project_root: str):
        self.root = Path(project_root).resolve()
        self.analyzer = ProjectAnalyzer(str(self.root))
        self.fixer = PythonFixer()

    def fix(self):
        issues = self.analyzer.analyze()
        print(f"Encontradas {len(issues)} issues para corrigir.")
        fixed_count = 0
        for issue in issues:
            if self._can_auto_fix(issue):
                print(f"Corrigindo: {issue}")
                if issue.file_path:
                    file_path = self.root / issue.file_path
                    if file_path.exists():
                        self.fixer.fix_file(file_path, issue)
                        fixed_count += 1
        print(f"Corrigidos {fixed_count} issues.")

    def _can_auto_fix(self, issue: Issue) -> bool:
        return issue.type in ('debug', 'structure', 'pep8')

import ast
from pathlib import Path
from utils.helpers import create_backup

class PythonFixer:
    def fix_file(self, file_path: Path, issue):
        create_backup(file_path)
        if issue.type == 'debug' and 'print()' in issue.message:
            self._comment_print_line(file_path, issue.line)
        self._validate_after_fix(file_path)

    def _comment_print_line(self, file_path: Path, line_no: int):
        try:
            text = file_path.read_text(encoding='utf-8')
            lines = text.splitlines(keepends=True)
            if 0 < line_no <= len(lines):
                line = lines[line_no - 1].lstrip('#').lstrip()
                if 'print(' in line:
                    lines[line_no - 1] = '# ' + line
                    file_path.write_text(''.join(lines), encoding='utf-8')
        except Exception as e:
            print(f"Erro ao fixar {file_path}: {e}")

    def _validate_after_fix(self, file_path: Path):
        try:
            with open(file_path, 'r', encoding='utf-8') as f:
                compile(f.read(), str(file_path), 'exec')
            print(f"✓ {file_path.name} validado.")
        except SyntaxError as e:
            print(f"✗ Erro de sintaxe após fix em {file_path}: {e}")
